#nullable enable // autogenerated

using System;
using PVZEngine;
using UnityEngine;

namespace MVZ2.UI
{
    public class OptionsDialogMoreOptionsPage : MonoBehaviour
    {
        public void UpdateOptions(MoreOptionsViewData viewData)
        {
            categories.updateList(viewData.categories.Length, (i, obj) =>
            {
                var category = obj.GetComponent<MoreOptionsCategory>();
                category.UpdateOptions(viewData.categories[i]);
            },
            obj =>
            {
                var category = obj.GetComponent<MoreOptionsCategory>();
                category.OnToggleValueChanged += OnToggleValueChangedCallback;
                category.OnSliderValueChanged += OnSliderValueChangedCallback;
                category.OnSliderEnd += OnSliderEndCallback;
                category.OnDropdownValueChanged += OnDropdownValueChangedCallback;
                category.OnButtonClicked += OnButtonClickedCallback;
                category.OnTooltipShow += OnTooltipShowCallback;
                category.OnTooltipHide += OnTooltipHideCallback;
            },
            obj =>
            {
                var category = obj.GetComponent<MoreOptionsCategory>();
                category.OnToggleValueChanged -= OnToggleValueChangedCallback;
                category.OnSliderValueChanged -= OnSliderValueChangedCallback;
                category.OnSliderEnd -= OnSliderEndCallback;
                category.OnDropdownValueChanged -= OnDropdownValueChangedCallback;
                category.OnButtonClicked -= OnButtonClickedCallback;
                category.OnTooltipShow -= OnTooltipShowCallback;
                category.OnTooltipHide -= OnTooltipHideCallback;
            });
        }
        public OptionWidgets? GetWidgetsByID(NamespaceID id)
        {
            foreach (var category in categories.getElements<MoreOptionsCategory>())
            {
                var widgets = category.GetWidgetsByID(id);
                if (widgets.Exists())
                    return widgets;
            }
            return null;
        }
        private void Awake()
        {
            moreBackButton.Button.onClick.AddListener(() => OnBackClick?.Invoke());
        }
        private void OnToggleValueChangedCallback(OptionWidgets widgets, bool value)
        {
            OnToggleValueChanged?.Invoke(widgets, value);
        }
        private void OnSliderValueChangedCallback(OptionWidgets widgets, float value)
        {
            OnSliderValueChanged?.Invoke(widgets, value);
        }
        private void OnSliderEndCallback(OptionWidgets widgets, float value)
        {
            OnSliderEnd?.Invoke(widgets, value);
        }
        private void OnDropdownValueChangedCallback(OptionWidgets widgets, int value)
        {
            OnDropdownValueChanged?.Invoke(widgets, value);
        }
        private void OnButtonClickedCallback(OptionWidgets widgets)
        {
            OnButtonClick?.Invoke(widgets);
        }
        private void OnTooltipShowCallback(TooltipHandler handler)
        {
            OnTooltipShow?.Invoke(handler);
        }
        private void OnTooltipHideCallback(TooltipHandler handler)
        {
            OnTooltipHide?.Invoke(handler);
        }

        public event Action<OptionWidgets, bool>? OnToggleValueChanged;
        public event Action<OptionWidgets, float>? OnSliderValueChanged;
        public event Action<OptionWidgets, float>? OnSliderEnd;
        public event Action<OptionWidgets, int>? OnDropdownValueChanged;
        public event Action<OptionWidgets>? OnButtonClick;
        public event Action<TooltipHandler>? OnTooltipShow;
        public event Action<TooltipHandler>? OnTooltipHide;

        public event Action? OnBackClick;
        [SerializeField]
        private ElementList categories = null!;
        [SerializeField]
        private TextButton moreBackButton = null!;
    }
    public struct MoreOptionsViewData
    {
        public MoreOptionsCategoryViewData[] categories;
    }
}
